// floor-plan-state.service.ts
import { Injectable, signal, computed } from '@angular/core';
import { FloorPlan, FloorPlanState, Table, TableFormData } from '../../models';

@Injectable({ providedIn: 'root' })
export class FloorPlanStateService {
  readonly isEditMode = computed(() => this.state().isEditMode);

  // Versioni mappa
  readonly currentVersion = computed(() => this.state().currentVersion);
  readonly activeVersion = computed(() => this.state().activeVersion);

  // Stato reattivo con signals
  private state = signal<FloorPlanState>({
  floorPlans: [],
  currentFloorPlan: null,
  tables: [],
  selectedTable: null,
  selectedTables: [],
  isDrawing: false,
  isMergeMode: false,
  isEditMode: false,
  currentVersion: 1,
  activeVersion: 1,
  showTableModal: false,
  showEditTableModal: false,
  showMergeModal: false,
  showDimensionsModal: false,
  tableForm: this.getDefaultTableForm()
  });

  // Computed values
  readonly floorPlans = computed(() => this.state().floorPlans);
  readonly currentFloorPlan = computed(() => this.state().currentFloorPlan);
  readonly tables = computed(() => this.state().tables);
  readonly selectedTable = computed(() => this.state().selectedTable);
  readonly selectedTables = computed(() => this.state().selectedTables);
  readonly isDrawing = computed(() => this.state().isDrawing);
  readonly isMergeMode = computed(() => this.state().isMergeMode);
  readonly showTableModal = computed(() => this.state().showTableModal);
  readonly showEditTableModal = computed(() => this.state().showEditTableModal);
  readonly showMergeModal = computed(() => this.state().showMergeModal);
  readonly showDimensionsModal = computed(() => this.state().showDimensionsModal);
  readonly tableForm = computed(() => this.state().tableForm);

  // Actions
  setFloorPlans(floorPlans: FloorPlan[]) {
    this.state.update(state => ({ ...state, floorPlans }));
  }

  setCurrentFloorPlan(floorPlan: FloorPlan | null) {
    this.state.update(state => ({ ...state, currentFloorPlan: floorPlan }));
  }

setTables(tables: Table[]) {
  console.log('🔵 setTables chiamato con', tables.length, 'tavoli');
  this.state.update(state => ({ ...state, tables }));
}

  setSelectedTable(table: Table | null) {
    this.state.update(state => ({ ...state, selectedTable: table }));
  }

  setSelectedTables(tables: Table[]) {
    this.state.update(state => ({ ...state, selectedTables: tables }));
  }

  setIsDrawing(isDrawing: boolean) {
    this.state.update(state => ({ ...state, isDrawing }));
  }

  setIsMergeMode(isMergeMode: boolean) {
    this.state.update(state => ({ ...state, isMergeMode }));
  }

  setShowTableModal(show: boolean) {
    this.state.update(state => ({ ...state, showTableModal: show }));
  }

  setShowEditTableModal(show: boolean) {
    this.state.update(state => ({ ...state, showEditTableModal: show }));
  }

  setShowMergeModal(show: boolean) {
    this.state.update(state => ({ ...state, showMergeModal: show }));
  }

  setShowDimensionsModal(show: boolean) {
    this.state.update(state => ({ ...state, showDimensionsModal: show }));
  }

  updateTableForm(updates: Partial<TableFormData>) {
    this.state.update(state => ({
      ...state,
      tableForm: { ...state.tableForm, ...updates }
    }));
  }

  resetTableForm() {
    this.state.update(state => ({
      ...state,
      tableForm: this.getDefaultTableForm()
    }));
  }

  addToSelectedTables(table: Table) {
    this.state.update(state => ({
      ...state,
      selectedTables: [...state.selectedTables, table]
    }));
  }

  removeFromSelectedTables(tableId: string) {
    this.state.update(state => ({
      ...state,
      selectedTables: state.selectedTables.filter(t => t.id !== tableId)
    }));
  }

  clearSelectedTables() {
    this.state.update(state => ({ ...state, selectedTables: [] }));
  }

  // Metodo per inizializzare il form con valori predefiniti basati sulla forma
initializeTableFormForShape(shapeType: string) {
  const currentForm = this.state().tableForm;
  
  switch (shapeType) {
    case 'circle':
      currentForm.borderRadius = 50;
      currentForm.gridHeight = currentForm.gridWidth; // Quadrato/circolo: altezza = larghezza
      currentForm.height = currentForm.width;         // Aggiorna anche height
      break;
    case 'square':
      currentForm.borderRadius = 12;
      currentForm.gridHeight = currentForm.gridWidth;
      currentForm.height = currentForm.width;
      break;
    case 'rectangle':
      currentForm.borderRadius = 8;
      break;
  }
  
  currentForm.shape = shapeType as any;
  
  this.state.update(state => ({ 
    ...state, 
    tableForm: { ...currentForm } 
  }));
}


  // Metodo per aggiornare il numero del tavolo automaticamente
  updateAutoTableNumber(nextNumber: number) {
    this.state.update(state => ({
      ...state,
      tableForm: { ...state.tableForm, tableNumber: nextNumber.toString() }
    }));
  }

  // Metodo per resettare completamente lo stato
  resetState() {
    this.state.set({
      floorPlans: [],
      currentFloorPlan: null,
      tables: [],
      selectedTable: null,
      selectedTables: [],
      isDrawing: false,
      isMergeMode: false,
      showTableModal: false,
      showEditTableModal: false,
      showMergeModal: false,
      showDimensionsModal: false,
      tableForm: this.getDefaultTableForm(),
      isEditMode: false,
      currentVersion: 1,
      activeVersion: 1,
    });
  }

private getDefaultTableForm(): TableFormData {
  const gridSize = 20; // Valore di default, sarà sovrascritto nel componente
  
  return {
    shape: 'rectangle',
    gridWidth: 6,
    gridHeight: 4,
    width: 6 * gridSize,
    height: 4 * gridSize,
    capacity: 2,
    borderRadius: 8,
    tableName: '',
    tableNumber: '',
    isOnlineBookable: true,
    isMerged: false  
  };
}


  resetForNewFloorPlan(): void {
  this.state.update(state => ({
    ...state,
    tables: [],
    selectedTable: null,
    selectedTables: [],
    isDrawing: false,
    isMergeMode: false,
    showTableModal: false,
    showEditTableModal: false,
    showMergeModal: false,
    showDimensionsModal: false
  }));
}


setIsEditMode(isEditMode: boolean) {
  this.state.update(state => ({ ...state, isEditMode }));
}

  // VERIONE MAPPA
  setCurrentVersion(version: number) {
    this.state.update(state => ({ ...state, currentVersion: version }));
  }

  setActiveVersion(version: number) {
    this.state.update(state => ({ ...state, activeVersion: version }));
  }
}