// table-rotation.service.ts
import { Injectable, inject } from '@angular/core';
import { TableService } from './table.service';
import { Table } from '../../models';

@Injectable({ providedIn: 'root' })
export class TableRotationService {
  private tableService = inject(TableService);

  // Ruota un tavolo (con il suo gruppo se unito)
  async rotateTable(table: Table, degrees: number): Promise<boolean> {
    try {
      // 1. Ottieni il tavolo principale per la rotazione
      const mainTable = this.getMainTableForRotation(table);
      if (!mainTable) {
        console.error('❌ Tavolo non valido per la rotazione');
        return false;
      }

      console.log(`🔄 Rotazione tavolo ${mainTable.table_number} di ${degrees}°`);

      // 2. Calcola la nuova rotazione
      const newRotation = (mainTable.rotation + degrees) % 360;

      // 3. Salva nel database (TableService farà l'aggiornamento ottimistico)
      const success = await this.tableService.rotateTable(mainTable.id, newRotation);

      if (!success) {
        console.error('❌ Errore nel salvataggio della rotazione');
        return false;
      }

      console.log('✅ Tavolo ruotato con successo');
      return true;

    } catch (error: any) {
      console.error('❌ Errore nella rotazione:', error);
      return false;
    }
  }

  // Ruota a un angolo specifico (0, 90, 180, 270)
  rotateToAngle(table: Table, angle: number): number {
    const currentRotation = table.rotation || 0;
    const degrees = angle - currentRotation;
    return ((degrees + 180) % 360) - 180; // percorso più breve
  }

  // Ottieni il tavolo principale per la rotazione
  private getMainTableForRotation(table: Table): Table | null {
    // Se è un figlio (parte di un tavolo unito), cerca il parent
    if (table.parent_table_id) {
      const parent = this.tableService.getTables().find(t => t.id === table.parent_table_id);
      return parent || table; // fallback al tavolo stesso
    }
    return table;
  }
}