  async onSaveDimensions() {
    const currentPlan = this.currentFloorPlan();
    if (!currentPlan) return;

    try {
      // ✅ MODIFICA: Controlla solo se ci sono tavoli nella mappa
      const tablesInCurrentPlan = this.tables().filter(table =>
        table.floor_plan_id === currentPlan.id
      );

      if (tablesInCurrentPlan.length > 0) {
        const outOfBoundsTables = tablesInCurrentPlan.filter(table => {
          return table.position_x + table.width > this.dimensionsForm.width ||
            table.position_y + table.height > this.dimensionsForm.height;
        });

        if (outOfBoundsTables.length > 0) {
          const shouldContinue = confirm(
            `${outOfBoundsTables.length} tavolo(i) escono dai nuovi bordi della mappa. Vuoi continuare? I tavoli verranno spostati automaticamente.`
          );

          if (!shouldContinue) return;

          for (const table of outOfBoundsTables) {
            table.position_x = Math.min(table.position_x, this.dimensionsForm.width - table.width);
            table.position_y = Math.min(table.position_y, this.dimensionsForm.height - table.height);
            await this.tableService.updateTable(table.id, {
              position_x: table.position_x,
              position_y: table.position_y
            });
          }
        }
      }

      const success = await this.floorPlanService.updateFloorPlan(currentPlan.id, {
        width: this.dimensionsForm.width,
        height: this.dimensionsForm.height
      });

      if (success) {
        const updatedPlan = { ...currentPlan, ...this.dimensionsForm };
        this.floorPlanStateService.setCurrentFloorPlan(updatedPlan);
        this.floorPlanStateService.setShowDimensionsModal(false);

        // Aggiorna dimensioni canvas
        this.updateCanvasDimensions();

        // ✅ AGGIUNGI: Messaggio di conferma
        console.log('✅ Dimensioni mappa aggiornate con successo');
      }
    } catch (error) {
      console.error('❌ Error updating floor plan dimensions:', error);
    }
  }

