  // METODI PER TAVOLI VICINI E UNIONE - RIPRISTINATI
  highlightAdjacentTables() {
    console.log('🎯 Mostra vicini - Inizio');

    // Resetta il messaggio precedente
    this.highlightMessage.set(null);

    // 1. Prendi tutti i tavoli visibili
    const allTables = this.tables();

    // Controlla se ci sono abbastanza tavoli
    if (allTables.length < 2) {
      this.highlightMessage.set('Ci sono meno di 2 tavoli nella mappa. Aggiungi altri tavoli per vedere quelli vicini.');
      console.warn('⚠️ Meno di 2 tavoli nella mappa');
      return;
    }

    console.log('📊 Tavoli totali:', allTables.length);

    // 2. Trova tutti i gruppi di tavoli adiacenti
    const groups = this.findAdjacentTableGroups(allTables);

    // Filtra solo i gruppi con almeno 2 tavoli (tavoli adiacenti)
    const adjacentGroups = groups.filter(group => group.length > 1);

    // 3. Controlla se ci sono tavoli adiacenti
    if (adjacentGroups.length === 0) {
      this.highlightMessage.set('Non ci sono tavoli vicini tra loro in questa mappa. Sposta i tavoli più vicini per poterli unire.');
      console.warn('⚠️ Nessun gruppo di tavoli adiacenti trovato');
      return;
    }

    console.log(`🔍 Trovati ${adjacentGroups.length} gruppi di tavoli adiacenti`);

    // Conta quanti tavoli sono adiacenti
    let totalAdjacentTables = 0;
    adjacentGroups.forEach(group => {
      totalAdjacentTables += group.length;
    });

    // Mostra messaggio informativo
    this.highlightMessage.set(
      `Trovati ${adjacentGroups.length} gruppi di tavoli adiacenti (${totalAdjacentTables} tavoli totali). L'evidenziazione verrà rimossa tra 5 secondi.`
    );

    // 4. Evidenzia i tavoli adiacenti
    adjacentGroups.forEach(group => {
      group.forEach(table => {
        this.highlightTable(table);
      });
    });

    // 5. Rimuovi evidenziazione dopo 5 secondi
    setTimeout(() => {
      this.clearAllHighlights();
      // Rimuovi anche il messaggio
      setTimeout(() => {
        this.highlightMessage.set(null);
      }, 500);
    }, 5000);
  }


  // Aggiungi questi metodi helper SEMPLICI:

  private findAdjacentTableGroups(tables: Table[]): Table[][] {
    const groups: Table[][] = [];
    const visited = new Set<string>();

    for (const table of tables) {
      if (!visited.has(table.id)) {
        // Trova tutti i tavoli collegati a questo
        const group = this.findConnectedTables(table, tables, visited);
        groups.push(group);
      }
    }

    return groups.filter(group => group.length > 0);
  }

  private findConnectedTables(startTable: Table, allTables: Table[], visited: Set<string>): Table[] {
    const group: Table[] = [];
    const queue: Table[] = [startTable];

    while (queue.length > 0) {
      const current = queue.shift()!;

      if (!visited.has(current.id)) {
        visited.add(current.id);
        group.push(current);

        // Trova i vicini di questo tavolo
        for (const otherTable of allTables) {
          if (!visited.has(otherTable.id) &&
            otherTable.id !== current.id &&
            this.floorPlanInteractionService.areTablesAdjacent(current, otherTable, 0)) { // gap=0 per contatto diretto
            queue.push(otherTable);
          }
        }
      }
    }

    return group;
  }

