  // METODI PER MOBILE - RIPRISTINATI
  private setupCanvasInteractions() {
    const canvas = this.canvasRef.nativeElement; // ora esiste sempre quando chiamato

    this.renderer.listen(canvas, 'click', (event) => this.onCanvasClick(event));
    this.renderer.listen(canvas, 'pointerdown', (event: PointerEvent) => this.onCanvasPointerDown(event));

    this.renderer.listen(canvas, 'touchstart', (event: TouchEvent) => {
      this.onCanvasTouchStart(event);
    }, { passive: false });

    this.renderer.listen(document, 'pointermove', () => {
      if (this.isDragging) {
        canvas.classList.add('dragging-active');
      }
    });

    this.renderer.listen(document, 'pointerup', () => {
      this.isDragging = false;
      canvas.classList.remove('dragging-active');
    });
  }


  private onCanvasPointerDown(event: PointerEvent) {
    if (this.isDrawing()) return;

    const target = event.target as HTMLElement;
    const tableElement = target.closest('.table-element') as HTMLElement | null;

    if (tableElement) {
      this.isDragging = true;
      const tableId = tableElement.getAttribute('data-table-id');
      const table = this.tables().find(t => t.id === tableId);

      if (table) {
        console.log('🟢 START DRAG for table:', table.table_number);

        tableElement.classList.add('dragging');
        tableElement.style.transition = 'none';

        this.selectTable(table);
        // Usa il servizio invece del metodo locale
        this.floorPlanInteractionService.startTableDrag(
          table.id,
          event,
          this.canvasRef.nativeElement,
          this.canvasScale()
        );
      }
    } else {
      this.deselectAll();
    }

    event.preventDefault();
    event.stopPropagation();
  }


private onCanvasTouchStart(event: TouchEvent) {
  if (this.isDrawing()) return;

  const target = event.target as HTMLElement;
  const tableElement = target.closest('.table-element') as HTMLElement | null;

  if (tableElement) {
    // Previeni lo scroll solo se l'evento è ancora cancellabile
    if (event.cancelable) {
      event.preventDefault();
    }
    
    // Se l'evento non è più cancellabile, significa che lo scroll è già iniziato,
    // quindi non possiamo più intercettarlo. In tal caso, non facciamo nulla.
    // Ma possiamo comunque tentare di selezionare il tavolo.
    
    const tableId = tableElement.getAttribute('data-table-id');
    const table = this.tables().find(t => t.id === tableId);

    if (table) {
      // Seleziona il tavolo (ma non avviare il drag se lo scroll è già iniziato)
      this.selectTable(table);
      
      // Se l'evento è cancellabile, possiamo anche avviare il drag
      if (event.cancelable) {
        this.isDragging = true;
        const touch = event.touches[0];
        const fakePointerEvent = new PointerEvent('pointerdown', {
          clientX: touch.clientX,
          clientY: touch.clientY,
          pointerId: 1
        });

        tableElement.classList.add('dragging');
        tableElement.style.transition = 'none';

        this.floorPlanInteractionService.startTableDrag(
          table.id, 
          fakePointerEvent, 
          this.canvasRef.nativeElement
        );
      } else {
        console.log('📱 Touch event non cancellabile, solo selezione');
      }
    }
  } else {
    this.deselectAll();
  }
}

  private setupPinchToZoom() {
    // ✅ AGGIUNGI QUESTO CONTROLLO
    if (!this.canvasRef?.nativeElement) {
      console.warn('Canvas ref non disponibile per pinch-to-zoom, rimando l\'inizializzazione');
      setTimeout(() => this.setupPinchToZoom(), 100);
      return;
    }

    const canvas = this.canvasRef.nativeElement;

    let initialDistance = 0;
    let initialScale = 0;

    this.renderer.listen(canvas, 'touchstart', (e: TouchEvent) => {
      if (e.touches.length === 2) {
        e.preventDefault();
        const touch1 = e.touches[0];
        const touch2 = e.touches[1];
        initialDistance = Math.hypot(
          touch2.clientX - touch1.clientX,
          touch2.clientY - touch1.clientY
        );
        initialScale = this.canvasScale();
      }
    }, { passive: false });

    this.renderer.listen(canvas, 'touchmove', (e: TouchEvent) => {
      if (e.touches.length === 2) {
        e.preventDefault();
        const touch1 = e.touches[0];
        const touch2 = e.touches[1];
        const currentDistance = Math.hypot(
          touch2.clientX - touch1.clientX,
          touch2.clientY - touch1.clientY
        );

        if (initialDistance > 0) {
          const scaleChange = currentDistance / initialDistance;
          const newScale = initialScale * scaleChange;

          const clampedScale = Math.max(0.3, Math.min(newScale, 3));
          this.canvasScale.set(clampedScale);

          this.updateCanvasDimensions();
        }
      }
    }, { passive: false });

    this.renderer.listen(canvas, 'touchend', () => {
      initialDistance = 0;
      initialScale = 0;
    });
  }

