import { Injectable, inject } from '@angular/core';
import { SupabaseService } from '../Base/supabase.service';
import { Table, TableMergeData } from '../../models';

@Injectable({
  providedIn: 'root'
})
export class TableMergeService {
  private supabaseService = inject(SupabaseService);

  async mergeTables(tables: Table[], mergeData: TableMergeData, floorPlanId: string, restaurantId: string): Promise<Table | null> {
    try {
      const tableIds = tables.map(t => t.id);

      // Crea il tavolo unito
      const mergedTable: Omit<Table, 'id' | 'created_at'> = {
        restaurant_id: restaurantId,
        floor_plan_id: floorPlanId,
        table_name: mergeData.table_name,
        table_number: mergeData.table_number,
        capacity: mergeData.capacity,
        shape: 'rectangle',
        position_x: mergeData.position_x,
        position_y: mergeData.position_y,
        width: mergeData.width,
        height: mergeData.height,
        rotation: 0,
        is_active: true,
        is_online_bookable: true,
        is_merged: false, // Questo è il tavolo principale, quindi non è merged
        parent_table_id: null, // Nessun parent perché è il principale
        merged_tables_ids: tableIds
      };

      // Inserisci il tavolo unito
      const { data: newTable, error } = await this.supabaseService.getSupabaseClient()
        .from('tables')
        .insert(mergedTable)
        .select()
        .single();

      if (error) throw error;

      // Aggiorna i tavoli originali per marcarli come uniti (figli)
      for (const table of tables) {
        const updateData = {
          is_online_bookable: false, // Non prenotabile online
          is_merged: true, // È un tavolo unito (figlio)
          parent_table_id: newTable.id // Riferimento al tavolo principale
        };

        const { error: updateError } = await this.supabaseService.getSupabaseClient()
          .from('tables')
          .update(updateData)
          .eq('id', table.id);

        if (updateError) throw updateError;
      }

      return newTable;
    } catch (error) {
      console.error('❌ Error merging tables:', error);
      return null;
    }
  }

  async splitMergedTable(mergedTable: Table): Promise<boolean> {
    try {
      console.log('🔍 Cerco tavoli figli per:', mergedTable.id);

      // Trova tutti i tavoli figli
      const { data: childTables, error: fetchError } = await this.supabaseService.getSupabaseClient()
        .from('tables')
        .select('*')
        .eq('parent_table_id', mergedTable.id);

      if (fetchError) {
        console.error('❌ Errore nel fetch dei tavoli figli:', fetchError);
        throw fetchError;
      }

      console.log('📋 Tavoli figli trovati:', childTables?.length);

      // Ripristina ogni tavolo figlio
      for (const table of childTables || []) {
        const updateData = {
          is_online_bookable: true,
          is_merged: false,
          parent_table_id: null
        };

        console.log('🔄 Ripristino tavolo:', table.table_number);

        const { error: updateError } = await this.supabaseService.getSupabaseClient()
          .from('tables')
          .update(updateData)
          .eq('id', table.id);

        if (updateError) {
          console.error('❌ Errore nell\'aggiornamento del tavolo:', updateError);
          throw updateError;
        }
      }

      // Elimina il tavolo unito (principale)
      console.log('🗑️ Elimino tavolo unito principale:', mergedTable.id);

      const { error: deleteError } = await this.supabaseService.getSupabaseClient()
        .from('tables')
        .delete()
        .eq('id', mergedTable.id);

      if (deleteError) {
        console.error('❌ Errore nell\'eliminazione del tavolo unito:', deleteError);
        throw deleteError;
      }

      console.log('✅ Separazione completata con successo');
      return true;
    } catch (error) {
      console.error('❌ Error splitting merged table:', error);
      return false;
    }
  }

  async getMergedTableChildren(parentTableId: string): Promise<Table[]> {
    try {
      const { data, error } = await this.supabaseService.getSupabaseClient()
        .from('tables')
        .select('*')
        .eq('parent_table_id', parentTableId);

      if (error) throw error;
      return data || [];
    } catch (error) {
      console.error('❌ Error fetching merged table children:', error);
      return [];
    }
  }
}